//-------------------------------------------------------------------------
// 엑셀 출력 (월별 재고 현황)
//-------------------------------------------------------------------------
scwin.f_Excel1 = async function() {
   if(ds_stock.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_stock.getTotalCol(); i++){
        if(gr_stock.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_stDt.getValue().trim(), "####/##");
    let str1 = $c.gus.cfGetFormatStr(ed_endDt.getValue().trim(), "####/##");
    let str2 = ed_reqOilStatNm.getValue(); 

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "월별 재고 현황",
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "기준일자 ["+ str +" ~ "+str1+ "]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff"  
    }]

    const options = {
        fileName: "월별 재고 현황"+".xlsx",
        sheetName: "월별 재고 현황" ,
        startRowIndex : 3,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_stock, options, infoArr);
};

//-------------------------------------------------------------------------
// 엑셀 출력 - 재고 추이(3개년)
//-------------------------------------------------------------------------
scwin.f_Excel2 = async function() {
   if(ds_stockprogress.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }

    let gridColCount = 0;
    for(let i = 0; i < gr_stockprogress.getTotalCol(); i++){
        if(gr_stockprogress.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_stDt.getValue().trim(), "####/##");
    let str1 = $c.gus.cfGetFormatStr(ed_endDt.getValue().trim(), "####-##");
    let str2 = ed_reqOilStatNm.getValue(); 

    let startRowIndex = 3;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "재고 추이(3개년)",
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "기준일자 ["+ str + "]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff"  
    }];
    const code = lc_item.getValue();
    const codeList = lc_item.getItemArray();    
    if ( code != "" && codeList.length > 0 ) {
        const text = codeList.find(item=>item.value == code)["orgLabel"];
        infoArr.push({
            rowIndex : 3,             
            colIndex : 0,           
            colSpan : gridColCount,  
            rowSpan : 1,
            text : "조회항목 ["+ text + "]",
            textAlign : "left",    
            fontSize : 10,
            drawBorder : false,       
            color : "black",       
            backgroundColor : "#ffffff"              
        });
        startRowIndex ++;
    }

    const options = {
        fileName: "재고 추이 3개년_"+".xlsx",
        sheetName: "재고 추이 3개년",
        startRowIndex : startRowIndex,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_stockprogress, options, infoArr);
};

