	    }else{
	 		//$c.gus.cfAlertMsg(MSG_CM_WRN_002);
            $c.win.alert("조회된 데이터가 없습니다.");
	    }
       return;
	} 

    if (rowCnt > 0) {
        totalRows.setValue(rowCnt);
        scwin.f_griddefault();     
    //   ds_stock.sort("stdYm", 0); 
    } 

};


